/**
 * Notification model and related types.
 *
 * All notification delivery in the system flows through these types.
 * The NotificationService receives domain events via the EventBus,
 * builds a NotificationPayload, and dispatches it through registered
 * NotificationAdapters (email, webhook, in-app, etc.).
 */

/**
 * Supported notification channels. Each channel corresponds to a
 * NotificationAdapter implementation.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app';

/**
 * Categories of notifications. Used by adapters to decide formatting
 * and priority.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'user_welcome'
  | 'user_updated';

/**
 * The payload passed to NotificationAdapters for delivery.
 * Adapters receive this and translate it to their channel-specific format.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  notificationType: NotificationType;
  metadata?: Record<string, unknown>;
}

/**
 * A persisted notification record — the result of a successful send.
 */
export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  notificationType: NotificationType;
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs email sends instead of
 * actually delivering them. Replace the send() body with a real
 * email provider (SendGrid, SES, SMTP, etc.) for production use.
 *
 * Implements NotificationAdapter so the NotificationService can
 * route email-channel notifications here.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Sender address shown in the From field. */
  fromAddress: string;
  /** Display name for the sender. */
  fromName: string;
}

const defaultEmailConfig: EmailConfig = {
  fromAddress: 'noreply@taskflowpro.com',
  fromName: 'TaskFlow Pro',
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: Array<{ to: string; subject: string; body: string; sentAt: Date }> = [];

  constructor(private config: EmailConfig = defaultEmailConfig) {}

  /**
   * Send an email notification.
   *
   * Stub: logs the email and stores it in memory for testing.
   * Replace with real email provider integration for production.
   */
  async send(payload: NotificationPayload): Promise<boolean> {
    try {
      this.logger.info(
        `Sending email from "${this.config.fromName} <${this.config.fromAddress}>" to ${payload.recipient}: ${payload.subject}`,
      );

      this.sentEmails.push({
        to: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        sentAt: new Date(),
      });

      return true;
    } catch (error) {
      this.logger.error(
        `Failed to send email to ${payload.recipient}: ${error instanceof Error ? error.message : String(error)}`,
      );
      return false;
    }
  }

  /**
   * Get all emails sent through this adapter (for testing).
   */
  getSentEmails(): Array<{ to: string; subject: string; body: string; sentAt: Date }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — the central hub for all notification delivery.
 *
 * ARCHITECTURE (Event-Driven):
 *   All notifications flow through this pattern:
 *   1. Domain services emit events via EventBus (e.g., 'order:created')
 *   2. NotificationService subscribes to relevant events
 *   3. Event handlers build a NotificationPayload
 *   4. The payload is dispatched to the appropriate NotificationAdapter
 *   5. The adapter delivers it (email, webhook, in-app, etc.)
 *
 * CONSTRAINTS:
 *   - All notifications MUST go through EventBus.emit() — no direct calls
 *   - All delivery channels MUST be implemented as NotificationAdapter
 *   - Adapters are registered at construction time via registerAdapter()
 *   - The NotificationService owns the notification lifecycle (creation,
 *     routing, persistence); adapters only handle delivery
 *
 * WHY EVENT-DRIVEN:
 *   - Domain services stay decoupled from notification concerns
 *   - Adding a new notification trigger = subscribing to an existing event
 *   - Adding a new channel = implementing NotificationAdapter
 *   - Event log provides auditability and replay capability
 *
 * Depends on:
 *   - EventBus (event system) for receiving ALL domain events
 *   - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is supported — later registrations
   * replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to domain events that should trigger notifications.
   * All event subscriptions are centralized here.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      this.handleUserCreated(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.dispatchNotification({
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: 'email',
      notificationType: 'order_confirmation',
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.dispatchNotification({
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: 'email',
      notificationType: 'order_status_update',
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Handle user created event — send welcome notification.
   */
  private handleUserCreated(event: UserCreatedEvent): void {
    this.logger.info(`Sending welcome notification for user ${event.user.id}`);

    this.dispatchNotification({
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro',
      body: `Welcome, ${event.user.name}! Your account has been created.`,
      channel: 'email',
      notificationType: 'user_welcome',
      metadata: { userId: event.user.id },
    });
  }

  /**
   * Dispatch a notification through the appropriate adapter and persist it.
   * If no adapter is registered for the channel, the notification is still
   * persisted (allows the service to work without adapters in tests).
   */
  private dispatchNotification(payload: NotificationPayload): void {
    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: payload.channel,
      notificationType: payload.notificationType,
      sentAt: new Date(),
      metadata: payload.metadata,
    };
    this.notifications.push(notification);

    const adapter = this.adapters.get(payload.channel);
    if (adapter) {
      adapter.send(payload).then((success) => {
        if (!success) {
          this.logger.warn(
            `Adapter delivery failed for notification ${notification.id} on channel ${payload.channel}`,
          );
        }
      });
    } else {
      this.logger.info(
        `No adapter registered for channel "${payload.channel}" — notification ${notification.id} persisted but not delivered`,
      );
    }

    this.logger.info(`Notification sent: ${notification.id} to ${payload.recipient}`);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

